const cityAliases = {
  'алматы': 'Алматы',
  'астана': 'Астана',
  'нур-султан': 'Астана',
  'нурсултан': 'Астана',
  'шымкент': 'Шымкент',
  'караганда': 'Караганда',
  'актау': 'Актау',
  'атырау': 'Атырау',
  'павлодар': 'Павлодар',
  'костанай': 'Костанай',
  'усть-каменогорск': 'Усть-Каменогорск',
};

const knownActivities = [
  'Строительство зданий и сооружений',
  'Консалтинговые услуги',
  'Образовательные услуги',
  'Телекоммуникации',
  'Розничная торговля',
  'Техническое обслуживание оборудования',
  'Производство продуктов питания',
  'Сельское хозяйство',
  'Добыча полезных ископаемых',
  'Транспорт и логистика',
  'Медицинские услуги',
  'Архитектура и проектирование',
  'Оптовая торговля',
  'Рекламные услуги',
  'Разработка программного обеспечения',
  'Юридические услуги',
  'Производство мебели',
  'Финансовые услуги',
  'Бухгалтерский учёт и аудит',
  'Ресторанный бизнес',
];

function compactText(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function normalizeForMatch(s) {
  return compactText(s)
    .toLowerCase()
    .replace(/["«»']/g, '')
    .replace(/\b(тоо|ао|ип)\b/gi, '')
    .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function detectCity(lower) {
  const cityRules = [
    { canon: 'Астана', regex: /(нур-?султан|астан)/i },
    { canon: 'Алматы', regex: /(алмат)/i },
    { canon: 'Шымкент', regex: /(шымкент)/i },
    { canon: 'Караганда', regex: /(караганд)/i },
    { canon: 'Актау', regex: /(актау)/i },
    { canon: 'Атырау', regex: /(атырау)/i },
    { canon: 'Павлодар', regex: /(павлодар)/i },
    { canon: 'Костанай', regex: /(костанай)/i },
    { canon: 'Усть-Каменогорск', regex: /(усть-?каменогорск)/i },
  ];

  for (const rule of cityRules) {
    if (rule.regex.test(lower)) return rule.canon;
  }

  for (const [alias, canon] of Object.entries(cityAliases)) {
    if (lower.includes(alias)) return canon;
  }

  return null;
}

function detectActivity(lower) {
  for (const v of knownActivities) {
    if (lower.includes(v.toLowerCase())) return v;
  }

  if (/(разработк|программ|it|айти|software|технолог)/i.test(lower)) return 'Разработка программного обеспечения';
  if (/(строит|construction|зданий|сооружений)/i.test(lower)) return 'Строительство зданий и сооружений';
  if (/(технич|обслуживан.*оборуд)/i.test(lower)) return 'Техническое обслуживание оборудования';
  if (/(архитект|проектирован)/i.test(lower)) return 'Архитектура и проектирование';
  if (/(транспорт|логист|доставк|склад)/i.test(lower)) return 'Транспорт и логистика';
  if (/(оптов)/i.test(lower)) return 'Оптовая торговля';
  if (/(рознич)/i.test(lower)) return 'Розничная торговля';
  if (/(финанс|банк|инвест|страх)/i.test(lower)) return 'Финансовые услуги';

  return null;
}

function normalizeLegalFormPrefix(s) {
  return compactText(s)
    .replace(/^тоо\b/i, 'ТОО')
    .replace(/^ао\b/i, 'АО')
    .replace(/^ип\b/i, 'ИП');
}

function detectCompanyName(chatInput) {
  const quotedLegal = chatInput.match(/(?:ТОО|АО|ИП)\s*["«][^"»]+["»]/i);
  if (quotedLegal && quotedLegal[0]) {
    const exact = normalizeLegalFormPrefix(quotedLegal[0].replace(/[«»]/g, '"'));
    const hint = normalizeForMatch(exact);
    return { exact, hint, confidence: 'high' };
  }

  const quotedAny = chatInput.match(/["«]([^"»]{2,})["»]/);
  if (quotedAny && quotedAny[1]) {
    const exact = compactText(quotedAny[1]);
    const hint = normalizeForMatch(exact);
    return { exact: null, hint, confidence: 'medium' };
  }

  const phrase = chatInput.match(/(?:компани[ияи]\s+|у\s+компани[ияи]\s+)([\p{L}\p{N}\s-]{3,})/iu);
  if (phrase && phrase[1]) {
    const raw = compactText(phrase[1]);
    const hint = normalizeForMatch(raw);
    if (hint) return { exact: null, hint, confidence: 'low' };
  }

  return { exact: null, hint: null, confidence: 'none' };
}

function needsSemanticFallback(lower, hasAnyFilter, queryMode) {
  if (queryMode === 'generic') return true;
  if (!hasAnyFilter && queryMode === 'list') return true;
  if (/(похож|аналог|схож|примерно|технологическ|что[- ]?то|какие\s+есть)/i.test(lower)) return true;
  return false;
}

return $input.all().map((item) => {
  const original = item.json || {};
  const chatInput = compactText(original.chatInput ?? '');
  const lower = chatInput.toLowerCase();

  const city = detectCity(lower);
  const activity = detectActivity(lower);
  const company = detectCompanyName(chatInput);

  const binMatch = chatInput.match(/\b\d{12}\b/);
  const bin = binMatch ? binMatch[0] : null;

  let status = null;
  if (/(неактив|ликвид|закрыт|приостанов)/i.test(lower)) status = 'Ликвидировано';
  else if (lower.includes('активн')) status = 'Активно';

  const isCount = /(сколько|количество|число)/i.test(lower);
  const isStatusLookup = /(какой\s+статус|статус\s+у\s+компани)/i.test(lower);
  const isDateLookup = /(дата\s+регистрац|когда\s+зарегистр)/i.test(lower);
  const isActivityLookup = /(вид\s+деятельност)/i.test(lower);
  const isList = /(найди|покажи|перечисли|какие|список|все|подбери)/i.test(lower);

  const asksUnsupportedField = /(выручк|доход|оборот|прибыл|маржин|ebitda|дивиденд|капитализац|активы|баланс|телефон|e-?mail|почт|сайт|адрес|руководител|учредител|директор|владелец|штат|сотрудник)/i.test(lower);
  const asksRankingWithoutMetric = /(крупнейш|топ\s*\d+|лучш(ий|ая|ие)|сам(ый|ая|ое|ые))/i.test(lower);

  let unsupportedReason = null;
  if (asksUnsupportedField) unsupportedReason = 'Запрошены поля, которых нет в источнике данных.';
  else if (asksRankingWithoutMetric) unsupportedReason = 'Запрошен рейтинг/сравнение, но в источнике нет метрик ранжирования.';

  let queryMode = 'generic';
  if (unsupportedReason) queryMode = 'unsupported';
  else if (isCount) queryMode = 'count';
  else if (bin) queryMode = 'bin_lookup';
  else if (isStatusLookup) queryMode = 'status_lookup';
  else if (isDateLookup) queryMode = 'registration_date_lookup';
  else if (isActivityLookup) queryMode = 'activity_lookup';
  else if (isList) queryMode = 'list';

  const must = [];
  if (bin) must.push({ key: 'metadata.bin', match: { value: bin } });
  if (company.exact) must.push({ key: 'metadata.name', match: { value: company.exact } });
  if (city) must.push({ key: 'metadata.city', match: { value: city } });
  if (status) must.push({ key: 'metadata.status', match: { value: status } });
  if (activity) must.push({ key: 'metadata.activity', match: { value: activity } });

  const qdrantFilter = must.length ? { must } : {};
  const hasAnyFilter = must.length > 0;

  let retrievalMode = 'semantic';
  if (queryMode === 'unsupported') retrievalMode = 'none';
  else if (!needsSemanticFallback(lower, hasAnyFilter, queryMode)) retrievalMode = 'metadata';

  const semanticTopK = queryMode === 'bin_lookup' ? 3 : 10;
  const metadataTopK = queryMode === 'count' ? 3000 : (queryMode === 'list' ? 100 : 25);

  const normalizedQuery = normalizeForMatch(chatInput);
  const cacheKey = normalizedQuery || lower;

  let cacheHit = false;
  let cachedResponseText = null;
  try {
    if (typeof $getWorkflowStaticData === 'function') {
      const s = $getWorkflowStaticData('global');
      s.answerCache = s.answerCache || {};
      if (s.answerCache[cacheKey]) {
        cacheHit = true;
        cachedResponseText = s.answerCache[cacheKey];
      }
    }
  } catch (e) {
    // Optional cache: no-op if static data API is unavailable in current runtime.
  }

  const filterParts = [];
  if (bin) filterParts.push(`бин=${bin}`);
  if (company.exact) filterParts.push(`название=${company.exact}`);
  if (city) filterParts.push(`город=${city}`);
  if (status) filterParts.push(`статус=${status}`);
  if (activity) filterParts.push(`вид_деятельности=${activity}`);

  const retrievalHint = [
    `query_mode=${queryMode}`,
    `retrieval_mode=${retrievalMode}`,
    unsupportedReason ? `unsupported_reason=${unsupportedReason}` : '',
    'Используй только факты из контекста.',
    'Если подходящих записей нет, верни недостаточно данных.',
  ].filter(Boolean).join('\n');

  const retrievalQuery = [
    retrievalHint,
    chatInput,
    filterParts.length ? `Фильтры: ${filterParts.join(', ')}` : '',
  ].filter(Boolean).join('\n');

  return {
    json: {
      ...original,
      chatInput,
      queryMode,
      retrievalMode,
      unsupportedReason,
      semanticTopK,
      metadataTopK,
      cacheKey,
      cacheHit,
      cachedResponseText,
      parsedFilters: {
        bin,
        companyName: company.exact,
        companyHint: company.hint,
        companyConfidence: company.confidence,
        city,
        status,
        activity,
      },
      qdrantFilter,
      retrievalQuery,
    },
  };
});

const items = $input.all();

function compact(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function normalizeForMatch(s) {
  return compact(s)
    .toLowerCase()
    .replace(/["«»']/g, '')
    .replace(/\b(тоо|ао|ип)\b/gi, '')
    .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function pickQueryItem(allItems) {
  return allItems.find((i) => {
    const j = i?.json || {};
    return Boolean(j.queryMode || j.qdrantFilter || j.parsedFilters || j.retrievalMode || j.cacheKey);
  }) || { json: {} };
}

function toRecordFromDocument(doc) {
  const m = doc?.metadata || {};
  const rec = {
    bin: compact(m.bin),
    name: compact(m.name),
    city: compact(m.city),
    status: compact(m.status),
    activity: compact(m.activity),
    registration_date: compact(m.registration_date),
  };
  if (!/^\d{12}$/.test(rec.bin)) return null;
  return rec;
}

const queryItem = pickQueryItem(items);
const query = queryItem.json || {};
const filters = (query.parsedFilters && typeof query.parsedFilters === 'object') ? query.parsedFilters : {};
const queryMode = compact(query.queryMode || 'generic');
const unsupportedReason = compact(query.unsupportedReason || '');

if (queryMode === 'unsupported' || unsupportedReason) {
  return [{ json: { response: { text: 'Недостаточно данных в контексте. Доступны только поля: БИН, название, город, статус, вид деятельности, дата регистрации.' } } }];
}

if (query.cacheHit && query.cachedResponseText) {
  return [{ json: { response: { text: String(query.cachedResponseText) } } }];
}

const docs = items
  .filter((i) => i?.json?.document)
  .map((i) => i.json.document)
  .filter(Boolean);

let records = docs.map(toRecordFromDocument).filter(Boolean);

const byBin = new Map();
for (const r of records) if (!byBin.has(r.bin)) byBin.set(r.bin, r);
records = [...byBin.values()];

function matchesStrictFilters(r) {
  if (filters.bin && r.bin !== String(filters.bin)) return false;
  if (filters.companyName && r.name !== String(filters.companyName)) return false;
  if (filters.city && r.city !== String(filters.city)) return false;
  if (filters.status && r.status !== String(filters.status)) return false;
  if (filters.activity && r.activity !== String(filters.activity)) return false;
  return true;
}

function scoreByCompanyHint(r) {
  const hint = normalizeForMatch(filters.companyHint || '');
  if (!hint) return 0;
  const n = normalizeForMatch(r.name);
  if (!n) return 0;
  if (n === hint) return 100;
  if (n.includes(hint)) return 80;
  if (hint.includes(n)) return 60;
  const hintTokens = new Set(hint.split(' ').filter(Boolean));
  const nameTokens = new Set(n.split(' ').filter(Boolean));
  if (!hintTokens.size || !nameTokens.size) return 0;
  let inter = 0;
  for (const t of hintTokens) if (nameTokens.has(t)) inter++;
  return Math.round((inter / hintTokens.size) * 40);
}

let filtered = records.filter(matchesStrictFilters);

if (!filtered.length && filters.companyHint) {
  filtered = records
    .map((r) => ({ r, s: scoreByCompanyHint(r) }))
    .filter((x) => x.s >= 40)
    .sort((a, b) => b.s - a.s)
    .map((x) => x.r);
}

if (!filtered.length) {
  return [{ json: { response: { text: 'Недостаточно данных в контексте.' } } }];
}

let answer = '';
if (queryMode === 'count') {
  const counted = Number(query.metadataCount || filtered.length || 0);
  answer = String(counted);
} else if (queryMode === 'status_lookup') {
  answer = filtered[0].status || 'Недостаточно данных в контексте.';
} else if (queryMode === 'registration_date_lookup') {
  answer = filtered[0].registration_date || 'Недостаточно данных в контексте.';
} else if (queryMode === 'activity_lookup') {
  answer = filtered[0].activity || 'Недостаточно данных в контексте.';
} else if (queryMode === 'bin_lookup') {
  const r = filtered[0];
  answer = `${r.name}, ${r.city}, ${r.status}`;
} else {
  const names = [...new Set(filtered.map((r) => r.name).filter(Boolean))].slice(0, 5);
  answer = names.length ? names.join(', ') : 'Недостаточно данных в контексте.';
}

const evidenceLines = filtered.slice(0, 3).map((r) => `Название: ${r.name} | БИН: ${r.bin} | Город: ${r.city} | Статус: ${r.status}`);

let finalText = answer;
if (evidenceLines.length) {
  finalText += '\n\nПодтверждение:\n' + evidenceLines.map((x) => `- ${x}`).join('\n');
}

try {
  if (typeof $getWorkflowStaticData === 'function' && query.cacheKey) {
    const s = $getWorkflowStaticData('global');
    s.answerCache = s.answerCache || {};
    s.answerCache[query.cacheKey] = finalText;
  }
} catch (e) {
  // Optional cache write: no-op if static data API is unavailable in current runtime.
}

return [{ json: { response: { text: finalText } } }];

const inputItems = $input.all();

function asArray(v) {
  return Array.isArray(v) ? v : [];
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function fetchWithTimeout(url, options, timeoutMs) {
  return await Promise.race([
    fetch(url, options),
    new Promise((_, reject) => {
      setTimeout(() => reject(new Error(`Timeout after ${timeoutMs}ms: ${url}`)), timeoutMs);
    }),
  ]);
}

async function postJson(baseUrl, path, body, timeoutMs = 2500) {
  const res = await fetchWithTimeout(`${baseUrl}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body || {}),
  }, timeoutMs);

  if (!res.ok) {
    const text = await res.text().catch(() => '');
    throw new Error(`HTTP ${res.status} ${path}: ${text.slice(0, 200)}`);
  }
  return await res.json();
}

async function postWithFallback(baseUrls, path, body, timeoutMs = 2500) {
  let lastErr = null;
  for (const baseUrl of baseUrls) {
    try {
      return await postJson(baseUrl, path, body, timeoutMs);
    } catch (err) {
      lastErr = err;
      await sleep(20);
    }
  }
  throw lastErr || new Error(`Request failed: ${path}`);
}

function toDocItemFromPayload(payload) {
  const metadata = payload?.metadata || {};
  const pageContent = payload?.pageContent || '';
  return {
    json: {
      document: {
        pageContent,
        metadata,
      },
    },
  };
}

async function run() {
  const output = [];

  for (const item of inputItems) {
    const query = item?.json || {};

    if (query.queryMode === 'unsupported' || query.retrievalMode === 'none' || query.cacheHit) {
      output.push({ json: { ...query } });
      continue;
    }

    const qdrantUrls = ['http://qdrant:6333', 'http://localhost:6333'];
    const ollamaUrls = ['http://ollama:11434', 'http://localhost:11434'];

    const filter = query.qdrantFilter || {};
    const hasFilter = Boolean(filter && Array.isArray(filter.must) && filter.must.length);

    if (query.retrievalMode === 'metadata') {
      const countBody = {
        exact: true,
        ...(hasFilter ? { filter } : {}),
      };

      const countRes = await postWithFallback(qdrantUrls, '/collections/kz_companies/points/count', countBody, 3000);

      const scrollBody = {
        limit: Number(query.metadataTopK || 50),
        with_payload: true,
        with_vector: false,
        ...(hasFilter ? { filter } : {}),
      };

      const scrollRes = await postWithFallback(qdrantUrls, '/collections/kz_companies/points/scroll', scrollBody, 4000);
      const points = asArray(scrollRes?.result?.points);

      output.push({ json: { ...query, metadataCount: Number(countRes?.result?.count || 0) } });
      for (const p of points) {
        output.push(toDocItemFromPayload(p?.payload || {}));
      }
      continue;
    }

    const embBody = {
      model: 'bge-m3:latest',
      prompt: query.retrievalQuery || query.chatInput || '',
    };
    const embRes = await postWithFallback(ollamaUrls, '/api/embeddings', embBody, 4000);
    const embedding = embRes?.embedding;
    if (!Array.isArray(embedding) || !embedding.length) {
      output.push({ json: { ...query, retrievalError: 'embedding_failed' } });
      continue;
    }

    const searchBody = {
      vector: embedding,
      limit: Number(query.semanticTopK || 10),
      with_payload: true,
      with_vector: false,
      ...(hasFilter ? { filter } : {}),
    };
    const searchRes = await postWithFallback(qdrantUrls, '/collections/kz_companies/points/search', searchBody, 4500);
    const hits = asArray(searchRes?.result);

    output.push({ json: { ...query } });
    for (const h of hits) {
      output.push(toDocItemFromPayload(h?.payload || {}));
    }
  }

  return output;
}

return run();
